import java.time.LocalTime;
import java.time.format.DateTimeFormatter;

public class Main {
    public static void main(String[] args) {
        // 現在の時間を取得
        LocalTime now = LocalTime.now();

        // 時間をフォーマット
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("HH:mm:ss");
        String formattedTime = now.format(formatter);

        // フォーマットされた時間を出力
        System.out.println(formattedTime);
        // 出力: 現在の時間（HH:mm:ss形式）
    }
}

import java.time.LocalTime;

public class Main {
    public static void main(String[] args) {
        // 時間を定義
        LocalTime time = LocalTime.of(8, 30, 0);

        // 時間に45分を加える
        LocalTime addedTime = time.plusMinutes(45);

        // 加算後の時間を出力
        System.out.println(addedTime);
        // 出力: 09:15:00
    }
}

import java.time.LocalTime;

public class Main {
    public static void main(String[] args) {
        // 2つの時間を定義
        LocalTime time1 = LocalTime.of(8, 30);
        LocalTime time2 = LocalTime.of(10, 15);

        // time1がtime2よりも前であるかを判定
        boolean isBefore = time1.isBefore(time2);

        // 判定結果を出力
        System.out.println(isBefore);
        // 出力: true
    }
}

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class Main {
