import java.time.LocalDateTime;

public class Main {
    public static void main(String[] args) {
        // 現在の日時を取得
        LocalDateTime now = LocalDateTime.now();

        // 日時に7日と30分を加える
        LocalDateTime addedDateTime = now.plusDays(7).plusMinutes(30);

        // 加算後の日時を出力
        System.out.println(addedDateTime);
        // 出力: 現在の日時から7日と30分後の日時
    }
}

import java.time.LocalDate;
import java.time.Period;

public class Main {
    public static void main(String[] args) {
        // 2つの日付を定義
        LocalDate date1 = LocalDate.of(2023, 5, 18);
        LocalDate date2 = LocalDate.of(2024, 5, 18);

        // 2つの日付間の期間を計算
        Period period = Period.between(date1, date2);
        int days = period.getDays();

        // 期間を出力
        System.out.println(days);
        // 出力: 365
    }
}

import java.time.LocalTime;
import java.time.Duration;

public class Main {
    public static void main(String[] args) {
        // 2つの時間を定義
        LocalTime time1 = LocalTime.of(10, 15);
        LocalTime time2 = LocalTime.of(12, 30);

        // 2つの時間間の差を計算
        Duration duration = Duration.between(time1, time2);
        long minutes = duration.toMinutes();

        // 時間の差を出力
        System.out.println(minutes);
        // 出力: 135
    }
}

import java.time.LocalDate;
import java.time.Period;

public class Main {
    public static void main(String[] args) {
        // 現在日付を取得
        LocalDate today = LocalDate.now();

        // 特定の日付を定義
        LocalDate futureDate = LocalDate.of(2025, 1, 1);

        // 2つの日付間の期間を計算
        Period period = Period.between(today, futureDate);
        int days = period.getDays();

        // 日数を出力
        System.out.println(days);
        // 出力: 日数（実行した日によります）
    }
}

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

public class Main {
    public static void main(String[] args) {
        // 現在日付を取得
        LocalDate today = LocalDate.now();

        // フォーマッターを定義
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy年MM月dd日");

        // 現在日付を指定した形式で表示
        String formattedDate = today.format(formatter);
        System.out.println(formattedDate);
        // 出力: YYYY年MM月DD日（実行した日によります）
    }
}

import java.time.LocalTime;
import java.time.format.DateTimeFormatter;

public class Main {
    public static void main(String[] args) {
        // 現在の時刻を取得
        LocalTime currentTime = LocalTime.now();

        // フォーマッターを定義
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("HH時mm分");

        // 現在の時刻を指定した形式で表示
        String formattedTime = currentTime.format(formatter);
        System.out.println(formattedTime);
        // 出力: HH時MM分（実行した時刻によります）
    }
}
